const CHAIN_STATS={totalTrades:1798,uniqueTraders:289,totalVolume:14474.94};

// ── FETCH LIVE WALLET HISTORY FROM ARCSCAN ───────────────────────────────────
async function fetchWalletLiveHistory(walletAddr) {
  try {
    const url = `https://testnet.arcscan.app/api/v2/addresses/${walletAddr}/transactions?filter=to&smart_contract=${CONTRACT_ADDRESS}`;
    const res = await fetch(url);
    if (!res.ok) throw new Error();
    const data = await res.json();
    const items = (data.items || []).filter(item =>
      item.method === "buyShares" && item.status === "ok"
    );
    const decoded = await Promise.all(items.map(async item => {
      const info = await fetchTxMarketId(item.hash);
      return {
        market: info ? getMarketName(info.marketId) : "Arcana Markets",
        side: info ? (info.isYes ? "YES" : "NO") : "—",
        amt: (parseFloat(item.value || 0) / 1e6).toFixed(2),
        txHash: item.hash,
        time: item.timestamp?.slice(0, 16) || "",
      };
    }));
    return decoded;
  } catch (e) {
    return [];
  }
}

// ── BUILD LEADERBOARD FROM REAL SEED + NEW SESSION TRADES ────────────────────
function buildLeaderboard(newTrades = []) {
  if (!newTrades || newTrades.length === 0) return LEADERBOARD_SEED;
  const merged = {};
  for (const row of LEADERBOARD_SEED) {
    merged[row.fullAddr.toLowerCase()] = { ...row };
  }
  for (const t of newTrades) {
    const key = t.from.toLowerCase();
    if (merged[key]) {
      merged[key].trades += 1;
    } else {
      merged[key] = {
        rank: 999, fullAddr: t.from,
        addr: `${t.from.slice(0, 6)}...${t.from.slice(-4)}`,
        trades: 1, badge: "",
      };
    }
  }
  return Object.values(merged)
    .sort((a, b) => b.trades - a.trades)
    .map((row, i) => ({
      ...row, rank: i + 1,
      badge: i === 0 ? "🥇" : i === 1 ? "🥈" : i === 2 ? "🥉" : "",
    }));
}

// ── BUILD STATS FROM REAL CHAIN DATA ─────────────────────────────────────────
function buildStats(newTrades = []) {
  const extraVol = (newTrades || []).reduce((s, t) => s + (parseFloat(t.usdc) || 0), 0);
  const totalVol = CHAIN_STATS.totalVolume + extraVol;
  const displayVol = totalVol >= 1000
    ? `$${(totalVol / 1000).toFixed(1)}K`
    : `$${totalVol.toFixed(0)}`;
  return {
    totalVolume: displayVol,
    traderCount: `${CHAIN_STATS.uniqueTraders}`,
    openMarkets: `${ALL_MARKETS.length}`,
  };
}

// ── BUILD ALL ACTIVITY: REAL SEED + NEW SESSION TRADES ───────────────────────
function buildAllActivity(newTrades = []) {
  const extra = (newTrades || []).map(t => ({
    from: t.from,
    shortAddr: `${t.from.slice(0, 6)}...${t.from.slice(-4)}`,
    txHash: t.txHash,
    time: t.time || new Date().toISOString().slice(0, 16),
  }));
  return [...extra, ...ACTIVITY_SEED];
}

// ── MARKET ID → NAME LOOKUP ──────────────────────────────────────────────────
function getMarketName(marketId) {
  const id = parseInt(marketId);
  return MC[`M${id}`] || `Market #${id}`;
}

// ── DECODE MARKET ID FROM TRANSACTION INPUT DATA ──────────────────────────────
async function fetchTxMarketId(txHash) {
  try {
    const url = `https://testnet.arcscan.app/api/v2/transactions/${txHash}`;
    const res = await fetch(url);
    if (!res.ok) return null;
    const data = await res.json();
    // input data: buyShares(uint256 _marketId, bool _isYes, uint256 _usdcAmount)
    // function selector = first 4 bytes, then 3 x 32 byte params
    const input = data.raw_input || data.input || "";
    if (input.length < 10) return null;
    const hex = input.replace("0x", "");
    // skip 8 chars (4 byte selector), first param is marketId (32 bytes = 64 hex chars)
    const marketIdHex = hex.slice(8, 72);
    const isYesHex = hex.slice(72, 136);
    const marketId = parseInt(marketIdHex, 16);
    const isYes = parseInt(isYesHex, 16) === 1;
    return { marketId, isYes };
  } catch (e) {
    return null;
  }
}

